const bool (&get_glyph_7x7(char c))[7][7] {
    switch (c) {
        case ' ': return G7_SPC;
        case '!': return G7_EXC; case '"': return G7_QUO; case '\'': return G7_SQU;
        case '(': return G7_LPA; case ')': return G7_RPA;
        case '*': return G7_MUL; case '+': return G7_PLU; case ',': return G7_COM;
        case '-': return G7_MIN; case '.': return G7_PER; case '/': return G7_DIV;
        case ':': return G7_COL; case ';': return G7_SMC;
        case '<': return G7_LT;  case '=': return G7_EQU; case '>': return G7_GT;
        case '?': return G7_QUE; case '%': return G7_PCT;
        
        case '0': return G7_0; case '1': return G7_1; case '2': return G7_2; case '3': return G7_3; case '4': return G7_4;
        case '5': return G7_5; case '6': return G7_6; case '7': return G7_7; case '8': return G7_8; case '9': return G7_9;

        case 'A': return G7_A; case 'B': return G7_B; case 'C': return G7_C; case 'D': return G7_D; case 'E': return G7_E;
        case 'F': return G7_F; case 'G': return G7_G; case 'H': return G7_H; case 'I': return G7_I; case 'J': return G7_J;
        case 'K': return G7_K; case 'L': return G7_L; case 'M': return G7_M; case 'N': return G7_N; case 'O': return G7_O;
        case 'P': return G7_P; case 'Q': return G7_Q; case 'R': return G7_R; case 'S': return G7_S; case 'T': return G7_T;
        case 'U': return G7_U; case 'V': return G7_V; case 'W': return G7_W; case 'X': return G7_X; case 'Y': return G7_Y; case 'Z': return G7_Z;

        case 'a': return G7_a; case 'b': return G7_b; case 'c': return G7_c; case 'd': return G7_d; case 'e': return G7_e;
        case 'f': return G7_f; case 'g': return G7_g; case 'h': return G7_h; case 'i': return G7_i; case 'j': return G7_j;
        case 'k': return G7_k; case 'l': return G7_l; case 'm': return G7_m; case 'n': return G7_n; case 'o': return G7_o;
        case 'p': return G7_p; case 'q': return G7_q; case 'r': return G7_r; case 's': return G7_s; case 't': return G7_t;
        case 'u': return G7_u; case 'v': return G7_v; case 'w': return G7_w; case 'x': return G7_x; case 'y': return G7_y; case 'z': return G7_z;

        default: return G7_UNK;
    }
}


